def setup_logging(
    log_dir: str = "/var/log/myapp",
    log_filename: str = "application.log",
    max_bytes: int = 10 * 1024 * 1024,  # 10 MB
    backup_count: int = 5,
    log_level: int = logging.DEBUG,
    file_permissions: int = 0o640,
    dir_permissions: int = 0o750,
):
    """
    Set up application logging with rotation and file permissions.

    Args:
        log_dir: Directory where log files will be stored
        log_filename: Name of the log file
        max_bytes: Maximum size of each log file before rotation
        backup_count: Number of backup log files to keep
        log_level: Logging level
        file_permissions: Unix file permissions for log files (owner rw, group r)
        dir_permissions: Unix directory permissions for log directory
    """
    # Create log directory if it doesn't exist
    log_path = Path(log_dir)
    try:
        log_path.mkdir(parents=True, exist_ok=True)
        os.chmod(log_dir, dir_permissions)
    except PermissionError:
        # Fallback to user's home directory if we can't write to the specified location
        log_dir = os.path.join(Path.home(), ".myapp", "logs")
        log_path = Path(log_dir)
        log_path.mkdir(parents=True, exist_ok=True)
        os.chmod(log_dir, dir_permissions)
        print(f"Warning: Using fallback log directory: {log_dir}", file=sys.stderr)

    log_file = os.path.join(log_dir, log_filename)

    # Create the root logger
    logger = logging.getLogger("myapp")
    logger.setLevel(log_level)

    # Clear any existing handlers
    logger.handlers.clear()

    # Define log format
    detailed_formatter = logging.Formatter(
        fmt="%(asctime)s | %(levelname)-8s | %(name)s | %(module)s:%(funcName)s:%(lineno)d | %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S",
    )

    simple_formatter = logging.Formatter(
        fmt="%(asctime)s | %(levelname)-8s | %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S",
    )

    # --- Rotating File Handler (size-based rotation) ---
    rotating_handler = logging.handlers.RotatingFileHandler(
        filename=log_file,
        maxBytes=max_bytes,
        backupCount=backup_count,
        encoding="utf-8",
    )
    rotating_handler.setLevel(logging.DEBUG)
    rotating_handler.setFormatter(detailed_formatter)
    logger.addHandler(rotating_handler)

    # Set file permissions on the log file
    _set_file_permissions(log_file, file_permissions)

    # --- Timed Rotating File Handler (time-based rotation) ---
    timed_log_file = os.path.join(log_dir, "application_daily.log")
    timed_handler = logging.handlers.TimedRotatingFileHandler(
        filename=timed_log_file,
        when="midnight",
        interval=1,
        backupCount=30,  # Keep 30 days of logs
        encoding="utf-8",
        utc=True,
    )
    timed_handler.setLevel(logging.INFO)
    timed_handler.setFormatter(detailed_formatter)
    timed_handler.suffix = "%Y-%m-%d"
    logger.addHandler(timed_handler)

    # Set file permissions on the timed log file
    _set_file_permissions(timed_log_file, file_permissions)

    # --- Error-only File Handler ---
    error_log_file = os.path.join(log_dir, "errors.log")
    error_handler = logging.handlers.RotatingFileHandler(
        filename=error_log_file,
        maxBytes=max_bytes,
        backupCount=backup_count,
        encoding="utf-8",
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(detailed_formatter)
    logger.addHandler(error_handler)

    # Set file permissions on the error log file
    _set_file_permissions(error_log_file, file_permissions)

    # --- Console Handler ---
    console_handler = logging.StreamHandler(sys.stdout)
    console_handler.setLevel(logging.INFO)
    console_handler.setFormatter(simple_formatter)
    logger.addHandler(console_handler)

    # Override the rotating handler's doRollover to set permissions on new files
    _patch_handler_rollover(rotating_handler, file_permissions)
    _patch_handler_rollover(error_handler, file_permissions)
    _patch_handler_rollover(timed_handler, file_permissions)

    logger.info("Logging system initialized successfully.")
    logger.info(f"Log directory: {log_dir}")
    logger.info(f"Log file: {log_file}")
    logger.info(f"Max file size: {max_bytes} bytes, Backup count: {backup_count}")
    logger.info(f"File permissions: {oct(file_permissions)}")

    return logger


def _set_file_permissions(filepath: str, permissions: int):
    """Set file permissions on a log file."""
    try:
        if os.path.exists(filepath):
            os.chmod(filepath, permissions)
            # Verify permissions
            current_perms = stat.S_IMODE(os.stat(filepath).st_mode)
            if current_perms != permissions:
                print(
                    f"Warning: Could not set permissions on {filepath}. "
                    f"Expected {oct(permissions)}, got {oct(current_perms)}",
                    file=sys.stderr,
                )
    except OSError as e:
        print(f"Warning: Failed to set permissions on {filepath}: {e}", file=sys.stderr)


def _patch_handler_rollover(handler, file_permissions: int):
    """
    Monkey-patch the handler's doRollover method to set file permissions
    on newly created log files after rotation.
    """
    original_do_rollover = handler.doRollover

    def patched_do_rollover():
        original_do_rollover()
        # Set permissions on the new log file
        if hasattr(handler, "baseFilename"):
            _set_file_permissions(handler.baseFilename, file_permissions)
            # Also set permissions on rotated backup files
            if isinstance(handler, logging.handlers.RotatingFileHandler):
                for i in range(1, handler.backupCount + 1):
                    backup_file = f"{handler.baseFilename}.{i}"
                    if os.path.exists(backup_file):
                        _set_file_permissions(backup_file, file_permissions)

    handler.doRollover = patched_do_rollover


def get_logger(name: str) -> logging.Logger:
    """Get a child logger under the myapp namespace."""
    return logging.getLogger(f"myapp.{name}")


def list_log_files(log_dir: str) -> list:
    """List all log files in the log directory with their sizes and permissions."""
    log_files = []
    if os.path.exists(log_dir):
        for filename in sorted(os.listdir(log_dir)):
            filepath = os.path.join(log_dir, filename)
            if os.path.isfile(filepath):
                file_stat = os.stat(filepath)
                log_files.append(
                    {
                        "filename": filename,
                        "filepath": filepath,
                        "size_bytes": file_stat.st_size,
                        "size_human": _human_readable_size(file_stat.st_size),
                        "permissions": oct(stat.S_IMODE(file_stat.st_mode)),
                        "owner_uid": file_stat.st_uid,
                        "group_gid": file_stat.st_gid,
                    }
                )
    return log_files


def _human_readable_size(size_bytes: int) -> str:
    """Convert bytes to human-readable format."""
    for unit in ["B", "KB", "MB", "GB"]:
        if size_bytes < 1024:
            return f"{size_bytes:.2f} {unit}"
        size_bytes /= 1024
    return f"{size_bytes:.2f} TB"


