class UserService:
    """Example service class demonstrating logging usage."""

    def __init__(self):
        self.logger = get_logger("user_service")

    def create_user(self, username: str, email: str):
        self.logger.info(f"Creating user: {username} ({email})")
        try:
            # Simulate user creation
            if not username or not email:
                raise ValueError("Username and email are required")
            if "@" not in email:
                raise ValueError(f"Invalid email format: {email}")
            self.logger.debug(f"User validation passed for: {username}")
            self.logger.info(f"User created successfully: {username}")
            return {"username": username, "email": email, "status": "active"}
        except ValueError as e:
            self.logger.error(f"Failed to create user '{username}': {e}")
            raise
        except Exception as e:
            self.logger.critical(f"Unexpected error creating user '{username}': {e}", exc_info=True)
            raise

    def delete_user(self, username: str):
        self.logger.warning(f"Deleting user: {username}")
        self.logger.info(f"User deleted: {username}")

    def get_user(self, username: str):
        self.logger.debug(f"Fetching user: {username}")
        return {"username": username, "status": "active"}


class OrderService:
    """Another example service class."""

    def __init__(self):
        self.logger = get_logger("order_service")

    def place_order(self, user: str, item: str, quantity: int):
        self.logger.info(f"Placing order: user={user}, item={item}, qty={quantity}")
        if quantity <= 0:
            self.logger.error(f"Invalid quantity: {quantity}")
            raise ValueError("Quantity must be positive")
        self.logger.info(f"Order placed successfully for {user}")
        return {"user": user, "item": item, "quantity": quantity, "status": "confirmed"}

    def cancel_order(self, order_id: str):
        self.logger.warning(f"Cancelling order: {order_id}")
        self.logger.info(f"Order {order_id} cancelled")


